def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        base_score = 0.0
        if ratio == 1:
            base_score = 0.0
        elif ratio > 1:
            base_score = np.inf
        else:
            for power in range(1, 21):
                if power % 3 == 0:
                    base_score += (ratio ** power) / (power + 1)
                elif power % 2 == 0:
                    base_score -= (ratio ** power) / (power * 2)
                else:
                    base_score += (ratio ** power) * (power / 10)
            if base_score < 0:
                base_score = abs(base_score)
            if base_score > 10:
                base_score = 10
        overlap_penalty = 0.0
        for offset in range(-4, 5):
            neighbor_idx = i + offset
            if neighbor_idx < 0 or neighbor_idx >= n or neighbor_idx == i:
                continue
            neighbor_capacity = bins[neighbor_idx]
            if neighbor_capacity <= 0:
                continue
            overlap_ratio = item / neighbor_capacity
            if overlap_ratio > 0 and overlap_ratio < 1:
                overlap_penalty += (1 - overlap_ratio) ** 3 / (abs(offset) + 1)
        capacity_diff_penalty = 0.0
        for j in range(n):
            if j == i or bins[j] <= 0:
                continue
            diff_ratio = abs(capacity - bins[j]) / max(capacity, bins[j])
            capacity_diff_penalty += diff_ratio / (abs(i-j)+1)
        proximity_factor = 0.0
        for step in range(1, 6):
            if i - step >= 0:
                dist = abs(bins[i] - bins[i - step])
                proximity_factor += dist / (step ** 2 + 1)
            if i + step < n:
                dist = abs(bins[i] - bins[i + step])
                proximity_factor += dist / (step ** 2 + 1)
        fragility = 0.0
        if capacity < item * 1.1:
            fragility = 5.0
        elif capacity < item * 1.5:
            fragility = 2.5
        elif capacity < item * 2.0:
            fragility = 1.0
        final_score = base_score + overlap_penalty + capacity_diff_penalty * 0.5 + proximity_factor * 0.3 + fragility
        if final_score < 0:
            final_score = 0
        priorities[i] = final_score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    min_finite = np.min(finite_priorities)
    max_finite = np.max(finite_priorities)
    range_finite = max_finite - min_finite if max_finite != min_finite else 1
    for idx in range(n):
        if not np.isfinite(priorities[idx]):
            priorities[idx] = max_finite + 10
        else:
            priorities[idx] = (priorities[idx] - min_finite) / range_finite
    return priorities
